+
+    /// Border color for unfocused widgets.
+    pub border: Color,
+    /// Border color for focused widgets.
+    pub border_focused: Color,
+}
+
+impl Default for Theme {
+    fn default() -> Self {
+        Self::dark()
+    }
+}
+
+impl Theme {
+    /// Create a dark theme (default).
+    pub fn dark() -> Self {
+        Self {
+            mode: ThemeMode::Dark,
