+        Style::default().fg(self.fg).bg(self.bg)
+    }
+
+    /// Get style for highlighted/selected items.
+    pub fn style_highlight(&self) -> Style {
+        Style::default()
+            .fg(self.highlight)
+            .add_modifier(Modifier::BOLD)
+    }
+
+    /// Get style for muted/secondary text.
